import { describe, expect, test } from '@a0n/gnosis/test';
import { runPatternHorizonBenchmark } from './pattern-horizon-benchmark';
import type { PatternHorizonCompilerInput } from '../pattern-horizon-compiler';

const READY_AUTHORITY = {
  plan: {
    pointIds: ['center'],
    samplesPerPoint: 1,
    maxAttemptsPerPoint: 1,
  },
  points: [
    {
      pointId: 'center',
      accepted: 1,
      rejected: 0,
      observed: 1,
    },
  ],
  modelSolved: true,
  frame: {
    gazePoint: { x: 500, y: 500 },
    zone: 'unavailable' as const,
    confidenceScore: 900,
    confidenceFloor: 600,
  },
  budget: {
    deadlineMs: 5,
    elapsedMs: 1,
  },
};

const DIRECT_READY: PatternHorizonCompilerInput = {
  kind: 'direct',
  generatedAt: '2026-04-11T00:00:00.000Z',
  source: 'bench-suite',
  phaseBeat: 0,
  horizonBeats: 2,
  catchToleranceBeats: 0.25,
  observationAuthority: READY_AUTHORITY,
  orbit: {
    period: 2,
    throws: [
      { beat: 0, fromHand: 'right', flightBeats: 3 },
      { beat: 1, fromHand: 'left', flightBeats: 3 },
    ],
  },
};

describe('gnosis pattern horizon benchmark', () => {
  test('reports compiler, baseline, and comparison metrics across disturbance scenarios', () => {
    const report = runPatternHorizonBenchmark([
      {
        scenarioId: 'ready-direct',
        label: 'Ready direct pattern',
        input: DIRECT_READY,
      },
      {
        scenarioId: 'blocked-authority',
        label: 'Observation authority broken',
        input: {
          ...DIRECT_READY,
          observationAuthority: {
            ...READY_AUTHORITY,
            points: [
              {
                pointId: 'center',
                accepted: 0,
                rejected: 1,
                observed: 1,
              },
            ],
            modelSolved: false,
          },
        },
      },
      {
        scenarioId: 'machine-only',
        label: 'Machine-only throw suppressed',
        input: {
          kind: 'direct',
          generatedAt: '2026-04-11T00:00:00.000Z',
          source: 'bench-suite',
          phaseBeat: 0,
          horizonBeats: 2,
          catchToleranceBeats: 0.25,
          observationAuthority: READY_AUTHORITY,
          orbit: {
            period: 2,
            throws: [
              {
                beat: 0,
                fromHand: 'right',
                flightBeats: 2,
                angleDeg: 0,
                speed: 3,
              },
              {
                beat: 0,
                fromHand: 'right',
                flightBeats: 3,
                angleDeg: 45,
                speed: 8,
              },
              { beat: 1, fromHand: 'left', flightBeats: 2 },
            ],
            machineOnlyMultiplexThreshold: 2,
            machineOnlyAngleThresholdDeg: 12,
            machineOnlySpeedRatioThreshold: 1.3,
          },
        },
      },
    ]);

    expect(report.label).toBe('gnosis-pattern-horizon-benchmark-v1');
    expect(report.scenarioCount).toBe(3);
    expect(report.compiler.commitRate).toBeCloseTo(2 / 3);
    expect(report.compiler.safeStateRate).toBeCloseTo(1 / 3);
    expect(report.baseline.commitRate).toBe(1);
    expect(report.comparisons.unsafeBaselineCommitsBlocked).toBe(1);
    expect(report.comparisons.machineOnlyBaselineSelectionsBlocked).toBe(1);
    expect(report.comparisons.sameSelectionRate).toBeGreaterThan(0);
    expect(report.compiler.meanCandidateCount).toBeGreaterThan(0);
    expect(
      report.scenarios.find(
        (scenario) => scenario.scenarioId === 'machine-only'
      )?.baselineSelectedMachineOnly
    ).toBe(true);
  });
});
